mapper.select:
select collect.*, user.name as userName, article.title as relName from `collect` left join `user` on collect.user_id = user.id left join `article` on collect.rel_id = article.id
and article.title like concat('%', #{relName}, '%') and collect.user_id = #{userId} and collect.rel_id = #{relId}
order by collect.id desc
